-- Web Empire 800 Tools Program — Initial Production Wave
-- Adds 88 deterministic, bilingual, production-ready formula tools.
-- Distribution: 8 tools across each of 11 categories.
-- Safe idempotent upserts. No destructive deletes.

begin;

insert into public.categories(
  slug, name_ar, name_en, description, icon, style_key, sort_order, is_active
)
values
  ('business-tools', 'أدوات الأعمال', 'Business Tools', 'أدوات القياس والتخطيط وتحسين أداء الأعمال.', 'briefcase', 'gold', 10, true),
  ('math-tools', 'أدوات حسابية', 'Math Tools', 'أدوات رياضية وحسابات هندسية ونسب ومتوسطات.', 'calculator', 'violet', 15, true),
  ('marketing-tools', 'أدوات التسويق', 'Marketing Tools', 'أدوات قياس كفاءة الحملات والعملاء والقنوات.', 'chart', 'cyan', 20, true),
  ('finance-tools', 'أدوات المال', 'Finance Tools', 'أدوات الميزانية والادخار والسيولة والالتزامات.', 'wallet', 'violet', 30, true),
  ('general-tools', 'أدوات عامة', 'General Tools', 'أدوات يومية للإنتاجية والتكاليف والمقارنات.', 'calculator', 'violet', 40, true),
  ('converter-tools', 'أدوات التحويل', 'Converter Tools', 'محولات وحدات دقيقة وسريعة.', 'convert', 'cyan', 50, true),
  ('date-time-tools', 'أدوات التاريخ والوقت', 'Date & Time Tools', 'أدوات الساعات والمدد والإنتاجية الزمنية.', 'calendar', 'gold', 60, true),
  ('health-tools', 'أدوات الصحة', 'Health Tools', 'حاسبات صحية تقديرية للاستخدام العام.', 'heart', 'violet', 130, true),
  ('education-tools', 'أدوات الطلاب', 'Education Tools', 'أدوات الدرجات والحضور والتخطيط الدراسي.', 'graduation-cap', 'cyan', 140, true),
  ('employment-tools', 'أدوات الرواتب والموظفين', 'Employment Tools', 'أدوات الرواتب والتعويضات والبدلات.', 'users', 'gold', 150, true),
  ('saudi-tools', 'أدوات السعودية', 'Saudi Tools', 'أدوات تقديرية شائعة للسوق السعودي.', 'landmark', 'gold', 190, true)
on conflict (slug) do update set
  name_ar = excluded.name_ar,
  name_en = excluded.name_en,
  description = excluded.description,
  icon = excluded.icon,
  style_key = excluded.style_key,
  sort_order = excluded.sort_order,
  is_active = excluded.is_active;

insert into public.category_translations(
  category_id, locale_id, name, description
)
select category.id, locale.id, seed.name, seed.description
from (
  values
    ('business-tools', 'ar', 'أدوات الأعمال', 'أدوات القياس والتخطيط وتحسين أداء الأعمال.'),
    ('business-tools', 'en', 'Business Tools', 'Business planning and performance tools.'),
    ('math-tools', 'ar', 'أدوات حسابية', 'أدوات رياضية وحسابات هندسية ونسب ومتوسطات.'),
    ('math-tools', 'en', 'Math Tools', 'Math, geometry, ratio, and average calculators.'),
    ('marketing-tools', 'ar', 'أدوات التسويق', 'أدوات قياس كفاءة الحملات والعملاء والقنوات.'),
    ('marketing-tools', 'en', 'Marketing Tools', 'Marketing campaign, customer, and channel metrics.'),
    ('finance-tools', 'ar', 'أدوات المال', 'أدوات الميزانية والادخار والسيولة والالتزامات.'),
    ('finance-tools', 'en', 'Finance Tools', 'Budgeting, savings, liquidity, and debt tools.'),
    ('general-tools', 'ar', 'أدوات عامة', 'أدوات يومية للإنتاجية والتكاليف والمقارنات.'),
    ('general-tools', 'en', 'General Tools', 'Everyday productivity, cost, and comparison tools.'),
    ('converter-tools', 'ar', 'أدوات التحويل', 'محولات وحدات دقيقة وسريعة.'),
    ('converter-tools', 'en', 'Converter Tools', 'Fast and accurate unit converters.'),
    ('date-time-tools', 'ar', 'أدوات التاريخ والوقت', 'أدوات الساعات والمدد والإنتاجية الزمنية.'),
    ('date-time-tools', 'en', 'Date & Time Tools', 'Hours, duration, and time-productivity tools.'),
    ('health-tools', 'ar', 'أدوات الصحة', 'حاسبات صحية تقديرية للاستخدام العام.'),
    ('health-tools', 'en', 'Health Tools', 'General health estimation calculators.'),
    ('education-tools', 'ar', 'أدوات الطلاب', 'أدوات الدرجات والحضور والتخطيط الدراسي.'),
    ('education-tools', 'en', 'Education Tools', 'Grades, attendance, and study planning tools.'),
    ('employment-tools', 'ar', 'أدوات الرواتب والموظفين', 'أدوات الرواتب والتعويضات والبدلات.'),
    ('employment-tools', 'en', 'Employment Tools', 'Salary, compensation, and allowance tools.'),
    ('saudi-tools', 'ar', 'أدوات السعودية', 'أدوات تقديرية شائعة للسوق السعودي.'),
    ('saudi-tools', 'en', 'Saudi Tools', 'Estimation tools for common Saudi use cases.')
) as seed(category_slug, locale_code, name, description)
join public.categories category on category.slug = seed.category_slug
join public.locales locale on locale.code = seed.locale_code
on conflict (category_id, locale_id) do update set
  name = excluded.name,
  description = excluded.description,
  updated_at = now();

create temporary table initial_800_tool_seed (
  category_slug text not null,
  slug text not null,
  title_ar text not null,
  title_en text not null,
  description_ar text not null,
  description_en text not null,
  runtime_config jsonb not null,
  input_fields jsonb not null,
  english_fields jsonb not null,
  submit_ar text not null,
  submit_en text not null,
  sort_order integer not null,
  is_featured boolean not null
) on commit drop;

insert into initial_800_tool_seed(
  category_slug, slug, title_ar, title_en, description_ar, description_en,
  runtime_config, input_fields, english_fields, submit_ar, submit_en,
  sort_order, is_featured
)
values
  ('business-tools', 'operating-leverage-calculator', 'حاسبة الرافعة التشغيلية', 'Operating Leverage Calculator', 'احسب درجة الرافعة التشغيلية من هامش المساهمة والربح التشغيلي.', 'Calculate operating leverage from contribution margin and operating income.', '{"expression":"contribution_margin / operating_income","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"درجة الرافعة التشغيلية","resultLabelEn":"Operating leverage","decimals":3,"showEquation":true}'::jsonb, '[{"key":"contribution_margin","label":"هامش المساهمة","type":"number","required":true,"min":0,"step":0.01},{"key":"operating_income","label":"الربح التشغيلي","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"contribution_margin","label":"Contribution margin","type":"number","required":true,"min":0,"step":0.01},{"key":"operating_income","label":"Operating income","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب الرافعة', 'Calculate leverage', 1000, true),
  ('business-tools', 'sales-per-employee-calculator', 'حاسبة المبيعات لكل موظف', 'Sales per Employee Calculator', 'احسب متوسط المبيعات التي يحققها كل موظف.', 'Calculate average sales generated per employee.', '{"expression":"annual_sales / employees","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"المبيعات لكل موظف","resultLabelEn":"Sales per employee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_sales","label":"المبيعات السنوية","type":"number","required":true,"min":0,"step":0.01},{"key":"employees","label":"عدد الموظفين","type":"number","required":true,"min":1,"step":1}]'::jsonb, '[{"key":"annual_sales","label":"Annual sales","type":"number","required":true,"min":0,"step":0.01},{"key":"employees","label":"Employees","type":"number","required":true,"min":1,"step":1}]'::jsonb, 'احسب المتوسط', 'Calculate average', 1001, false),
  ('business-tools', 'revenue-per-customer-calculator', 'حاسبة الإيراد لكل عميل', 'Revenue per Customer Calculator', 'احسب متوسط الإيراد الناتج من كل عميل.', 'Calculate average revenue generated per customer.', '{"expression":"revenue / customers","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الإيراد لكل عميل","resultLabelEn":"Revenue per customer","decimals":2,"showEquation":true}'::jsonb, '[{"key":"revenue","label":"إجمالي الإيراد","type":"number","required":true,"min":0,"step":0.01},{"key":"customers","label":"عدد العملاء","type":"number","required":true,"min":1,"step":1}]'::jsonb, '[{"key":"revenue","label":"Total revenue","type":"number","required":true,"min":0,"step":0.01},{"key":"customers","label":"Customers","type":"number","required":true,"min":1,"step":1}]'::jsonb, 'احسب الإيراد', 'Calculate revenue', 1002, false),
  ('business-tools', 'inventory-days-calculator', 'حاسبة أيام المخزون', 'Inventory Days Calculator', 'قدّر متوسط عدد الأيام التي يبقى فيها المخزون قبل بيعه.', 'Estimate how many days inventory remains before being sold.', '{"expression":"average_inventory / cost_of_sales * 365","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"أيام المخزون","resultLabelEn":"Inventory days","decimals":2,"showEquation":true}'::jsonb, '[{"key":"average_inventory","label":"متوسط المخزون","type":"number","required":true,"min":0,"step":0.01},{"key":"cost_of_sales","label":"تكلفة المبيعات السنوية","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"average_inventory","label":"Average inventory","type":"number","required":true,"min":0,"step":0.01},{"key":"cost_of_sales","label":"Annual cost of sales","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب أيام المخزون', 'Calculate inventory days', 1003, false),
  ('business-tools', 'receivable-days-calculator', 'حاسبة أيام التحصيل', 'Receivable Days Calculator', 'قدّر متوسط أيام تحصيل المبيعات الآجلة.', 'Estimate average collection days for credit sales.', '{"expression":"average_receivables / credit_sales * 365","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"أيام التحصيل","resultLabelEn":"Receivable days","decimals":2,"showEquation":true}'::jsonb, '[{"key":"average_receivables","label":"متوسط الذمم المدينة","type":"number","required":true,"min":0,"step":0.01},{"key":"credit_sales","label":"المبيعات الآجلة السنوية","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"average_receivables","label":"Average receivables","type":"number","required":true,"min":0,"step":0.01},{"key":"credit_sales","label":"Annual credit sales","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب أيام التحصيل', 'Calculate collection days', 1004, false),
  ('business-tools', 'payable-days-calculator', 'حاسبة أيام السداد', 'Payable Days Calculator', 'قدّر متوسط الأيام التي تستغرقها المنشأة لسداد الموردين.', 'Estimate average days taken to pay suppliers.', '{"expression":"average_payables / purchases * 365","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"أيام السداد","resultLabelEn":"Payable days","decimals":2,"showEquation":true}'::jsonb, '[{"key":"average_payables","label":"متوسط الذمم الدائنة","type":"number","required":true,"min":0,"step":0.01},{"key":"purchases","label":"المشتريات السنوية","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"average_payables","label":"Average payables","type":"number","required":true,"min":0,"step":0.01},{"key":"purchases","label":"Annual purchases","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب أيام السداد', 'Calculate payable days', 1005, false),
  ('business-tools', 'cash-conversion-cycle-calculator', 'حاسبة دورة التحويل النقدي', 'Cash Conversion Cycle Calculator', 'احسب مدة دورة التحويل النقدي من أيام المخزون والتحصيل والسداد.', 'Calculate cash conversion cycle from inventory, receivable, and payable days.', '{"expression":"inventory_days + receivable_days - payable_days","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"دورة التحويل النقدي","resultLabelEn":"Cash conversion cycle","decimals":2,"showEquation":true}'::jsonb, '[{"key":"inventory_days","label":"أيام المخزون","type":"number","required":true,"min":0,"step":0.1},{"key":"receivable_days","label":"أيام التحصيل","type":"number","required":true,"min":0,"step":0.1},{"key":"payable_days","label":"أيام السداد","type":"number","required":true,"min":0,"step":0.1}]'::jsonb, '[{"key":"inventory_days","label":"Inventory days","type":"number","required":true,"min":0,"step":0.1},{"key":"receivable_days","label":"Receivable days","type":"number","required":true,"min":0,"step":0.1},{"key":"payable_days","label":"Payable days","type":"number","required":true,"min":0,"step":0.1}]'::jsonb, 'احسب الدورة', 'Calculate cycle', 1006, true),
  ('business-tools', 'customer-concentration-calculator', 'حاسبة تركّز العملاء', 'Customer Concentration Calculator', 'احسب نسبة الإيراد القادم من أكبر عميل إلى إجمالي الإيراد.', 'Calculate the share of total revenue generated by the largest customer.', '{"expression":"largest_customer_revenue / total_revenue * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة تركّز العملاء","resultLabelEn":"Customer concentration","decimals":2,"showEquation":true}'::jsonb, '[{"key":"largest_customer_revenue","label":"إيراد أكبر عميل","type":"number","required":true,"min":0,"step":0.01},{"key":"total_revenue","label":"إجمالي الإيراد","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"largest_customer_revenue","label":"Largest customer revenue","type":"number","required":true,"min":0,"step":0.01},{"key":"total_revenue","label":"Total revenue","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب التركّز', 'Calculate concentration', 1007, false),
  ('math-tools', 'weighted-mean-calculator', 'حاسبة المتوسط المرجّح', 'Weighted Mean Calculator', 'احسب المتوسط المرجّح لقيمتين حسب الوزن.', 'Calculate the weighted mean of two values.', '{"expression":"(value_a * weight_a + value_b * weight_b) / (weight_a + weight_b)","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"المتوسط المرجّح","resultLabelEn":"Weighted mean","decimals":2,"showEquation":true}'::jsonb, '[{"key":"value_a","label":"القيمة الأولى","type":"number","required":true,"step":0.01},{"key":"weight_a","label":"وزن القيمة الأولى","type":"number","required":true,"min":0,"step":0.01},{"key":"value_b","label":"القيمة الثانية","type":"number","required":true,"step":0.01},{"key":"weight_b","label":"وزن القيمة الثانية","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"value_a","label":"First value","type":"number","required":true,"step":0.01},{"key":"weight_a","label":"First weight","type":"number","required":true,"min":0,"step":0.01},{"key":"value_b","label":"Second value","type":"number","required":true,"step":0.01},{"key":"weight_b","label":"Second weight","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب المتوسط', 'Calculate mean', 1100, true),
  ('math-tools', 'proportion-value-calculator', 'حاسبة التناسب', 'Proportion Value Calculator', 'أوجد القيمة المجهولة في معادلة تناسب بسيطة.', 'Find the unknown value in a simple proportion.', '{"expression":"b * c / a","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"القيمة المجهولة","resultLabelEn":"Unknown value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"a","label":"A","type":"number","required":true,"min":1e-06,"step":0.01},{"key":"b","label":"B","type":"number","required":true,"step":0.01},{"key":"c","label":"C","type":"number","required":true,"step":0.01}]'::jsonb, '[{"key":"a","label":"A","type":"number","required":true,"min":1e-06,"step":0.01},{"key":"b","label":"B","type":"number","required":true,"step":0.01},{"key":"c","label":"C","type":"number","required":true,"step":0.01}]'::jsonb, 'احسب القيمة', 'Calculate value', 1101, false),
  ('math-tools', 'geometric-mean-two-values', 'حاسبة المتوسط الهندسي', 'Geometric Mean Calculator', 'احسب المتوسط الهندسي لقيمتين موجبتين.', 'Calculate the geometric mean of two positive values.', '{"expression":"(value_a * value_b) ^ 0.5","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"المتوسط الهندسي","resultLabelEn":"Geometric mean","decimals":2,"showEquation":true}'::jsonb, '[{"key":"value_a","label":"القيمة الأولى","type":"number","required":true,"min":0,"step":0.01},{"key":"value_b","label":"القيمة الثانية","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"value_a","label":"First value","type":"number","required":true,"min":0,"step":0.01},{"key":"value_b","label":"Second value","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب المتوسط', 'Calculate mean', 1102, false),
  ('math-tools', 'harmonic-mean-two-values', 'حاسبة المتوسط التوافقي', 'Harmonic Mean Calculator', 'احسب المتوسط التوافقي لقيمتين موجبتين.', 'Calculate the harmonic mean of two positive values.', '{"expression":"2 * value_a * value_b / (value_a + value_b)","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"المتوسط التوافقي","resultLabelEn":"Harmonic mean","decimals":2,"showEquation":true}'::jsonb, '[{"key":"value_a","label":"القيمة الأولى","type":"number","required":true,"min":1e-06,"step":0.01},{"key":"value_b","label":"القيمة الثانية","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"value_a","label":"First value","type":"number","required":true,"min":1e-06,"step":0.01},{"key":"value_b","label":"Second value","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب المتوسط', 'Calculate mean', 1103, false),
  ('math-tools', 'square-diagonal-calculator', 'حاسبة قطر المربع', 'Square Diagonal Calculator', 'احسب طول قطر المربع من طول الضلع.', 'Calculate a square diagonal from side length.', '{"expression":"side * (2 ^ 0.5)","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"قطر المربع","resultLabelEn":"Square diagonal","decimals":2,"showEquation":true}'::jsonb, '[{"key":"side","label":"طول الضلع","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"side","label":"Side length","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب القطر', 'Calculate diagonal', 1104, false),
  ('math-tools', 'circle-circumference-calculator', 'حاسبة محيط الدائرة', 'Circle Circumference Calculator', 'احسب محيط الدائرة من نصف القطر.', 'Calculate circle circumference from radius.', '{"expression":"2 * 3.141592653589793 * radius","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"محيط الدائرة","resultLabelEn":"Circle circumference","decimals":2,"showEquation":true}'::jsonb, '[{"key":"radius","label":"نصف القطر","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"radius","label":"Radius","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب المحيط', 'Calculate circumference', 1105, false),
  ('math-tools', 'trapezoid-area-calculator', 'حاسبة مساحة شبه المنحرف', 'Trapezoid Area Calculator', 'احسب مساحة شبه المنحرف من القاعدتين والارتفاع.', 'Calculate trapezoid area from two bases and height.', '{"expression":"(base_a + base_b) * height / 2","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"مساحة شبه المنحرف","resultLabelEn":"Trapezoid area","decimals":2,"showEquation":true}'::jsonb, '[{"key":"base_a","label":"القاعدة الأولى","type":"number","required":true,"min":0,"step":0.01},{"key":"base_b","label":"القاعدة الثانية","type":"number","required":true,"min":0,"step":0.01},{"key":"height","label":"الارتفاع","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"base_a","label":"First base","type":"number","required":true,"min":0,"step":0.01},{"key":"base_b","label":"Second base","type":"number","required":true,"min":0,"step":0.01},{"key":"height","label":"Height","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب المساحة', 'Calculate area', 1106, false),
  ('math-tools', 'regular-polygon-angle-calculator', 'حاسبة زاوية المضلع المنتظم', 'Regular Polygon Angle Calculator', 'احسب قياس الزاوية الداخلية للمضلع المنتظم.', 'Calculate the interior angle of a regular polygon.', '{"expression":"(sides - 2) * 180 / sides","outputUnitAr":"°","outputUnitEn":"°","resultLabelAr":"الزاوية الداخلية","resultLabelEn":"Interior angle","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sides","label":"عدد الأضلاع","type":"number","required":true,"min":3,"step":1}]'::jsonb, '[{"key":"sides","label":"Number of sides","type":"number","required":true,"min":3,"step":1}]'::jsonb, 'احسب الزاوية', 'Calculate angle', 1107, false),
  ('date-time-tools', 'minutes-to-decimal-hours', 'محول الدقائق إلى ساعات عشرية', 'Minutes to Decimal Hours', 'حوّل عدد الدقائق إلى ساعات بصيغة عشرية.', 'Convert minutes to decimal hours.', '{"expression":"minutes / 60","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"الساعات العشرية","resultLabelEn":"Decimal hours","decimals":2,"showEquation":true}'::jsonb, '[{"key":"minutes","label":"الدقائق","type":"number","required":true,"min":0,"step":1}]'::jsonb, '[{"key":"minutes","label":"Minutes","type":"number","required":true,"min":0,"step":1}]'::jsonb, 'حوّل إلى ساعات', 'Convert to hours', 1200, true),
  ('date-time-tools', 'decimal-hours-to-minutes', 'محول الساعات العشرية إلى دقائق', 'Decimal Hours to Minutes', 'حوّل الساعات العشرية إلى دقائق.', 'Convert decimal hours to minutes.', '{"expression":"hours * 60","outputUnitAr":" دقيقة","outputUnitEn":" minutes","resultLabelAr":"إجمالي الدقائق","resultLabelEn":"Total minutes","decimals":2,"showEquation":true}'::jsonb, '[{"key":"hours","label":"الساعات العشرية","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"hours","label":"Decimal hours","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'حوّل إلى دقائق', 'Convert to minutes', 1201, false),
