  ('date-time-tools', 'meeting-person-hours-calculator', 'حاسبة ساعات العمل في الاجتماع', 'Meeting Person-Hours Calculator', 'احسب إجمالي ساعات الأشخاص المستهلكة في اجتماع.', 'Calculate total person-hours consumed by a meeting.', '{"expression":"attendees * duration_hours","outputUnitAr":" ساعة-شخص","outputUnitEn":" person-hours","resultLabelAr":"إجمالي ساعات الأشخاص","resultLabelEn":"Total person-hours","decimals":2,"showEquation":true}'::jsonb, '[{"key":"attendees","label":"عدد الحضور","type":"number","required":true,"min":1,"step":1},{"key":"duration_hours","label":"مدة الاجتماع بالساعات","type":"number","required":true,"min":0,"step":0.25}]'::jsonb, '[{"key":"attendees","label":"Attendees","type":"number","required":true,"min":1,"step":1},{"key":"duration_hours","label":"Meeting duration in hours","type":"number","required":true,"min":0,"step":0.25}]'::jsonb, 'احسب ساعات الأشخاص', 'Calculate person-hours', 1205, false),
