  ('health-tools', 'target-weight-by-bmi', 'حاسبة الوزن المستهدف حسب BMI', 'Target Weight by BMI', 'قدّر الوزن الموافق لمؤشر كتلة مستهدف وطول محدد.', 'Estimate weight matching a target BMI and height.', '{"expression":"target_bmi * ((height_cm / 100) ^ 2)","outputUnitAr":" كجم","outputUnitEn":" kg","resultLabelAr":"الوزن التقديري","resultLabelEn":"Estimated weight","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية عامة ولا تغني عن استشارة مختص صحي.","noteEn":"This is a general estimate and not a substitute for professional medical advice."}'::jsonb, '[{"key":"target_bmi","label":"مؤشر BMI المستهدف","type":"number","required":true,"min":1,"step":0.1,"defaultValue":22},{"key":"height_cm","label":"الطول بالسنتيمتر","type":"number","required":true,"min":1,"step":0.1}]'::jsonb, '[{"key":"target_bmi","label":"Target BMI","type":"number","required":true,"min":1,"step":0.1,"defaultValue":22},{"key":"height_cm","label":"Height in cm","type":"number","required":true,"min":1,"step":0.1}]'::jsonb, 'احسب الوزن', 'Calculate weight', 1300, true),
  ('health-tools', 'walking-pace-calculator', 'حاسبة وتيرة المشي', 'Walking Pace Calculator', 'احسب عدد الدقائق لكل كيلومتر أثناء المشي.', 'Calculate walking pace in minutes per kilometer.', '{"expression":"minutes / distance_km","outputUnitAr":" دقيقة/كم","outputUnitEn":" min/km","resultLabelAr":"وتيرة المشي","resultLabelEn":"Walking pace","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية عامة ولا تغني عن استشارة مختص صحي.","noteEn":"This is a general estimate and not a substitute for professional medical advice."}'::jsonb, '[{"key":"minutes","label":"المدة بالدقائق","type":"number","required":true,"min":0,"step":0.1},{"key":"distance_km","label":"المسافة بالكيلومتر","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, '[{"key":"minutes","label":"Duration in minutes","type":"number","required":true,"min":0,"step":0.1},{"key":"distance_km","label":"Distance in km","type":"number","required":true,"min":1e-06,"step":0.01}]'::jsonb, 'احسب الوتيرة', 'Calculate pace', 1301, false),
  ('health-tools', 'running-speed-calculator', 'حاسبة سرعة الجري', 'Running Speed Calculator', 'احسب متوسط سرعة الجري بالكيلومتر في الساعة.', 'Calculate average running speed in kilometers per hour.', '{"expression":"distance_km / (minutes / 60)","outputUnitAr":" كم/س","outputUnitEn":" km/h","resultLabelAr":"متوسط السرعة","resultLabelEn":"Average speed","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية عامة ولا تغني عن استشارة مختص صحي.","noteEn":"This is a general estimate and not a substitute for professional medical advice."}'::jsonb, '[{"key":"distance_km","label":"المسافة بالكيلومتر","type":"number","required":true,"min":0,"step":0.01},{"key":"minutes","label":"المدة بالدقائق","type":"number","required":true,"min":1e-06,"step":0.1}]'::jsonb, '[{"key":"distance_km","label":"Distance in km","type":"number","required":true,"min":0,"step":0.01},{"key":"minutes","label":"Duration in minutes","type":"number","required":true,"min":1e-06,"step":0.1}]'::jsonb, 'احسب السرعة', 'Calculate speed', 1302, false),
