  ('health-tools', 'body-fat-mass-calculator', 'حاسبة كتلة الدهون', 'Body Fat Mass Calculator', 'احسب كتلة الدهون التقديرية من الوزن ونسبة الدهون.', 'Calculate estimated fat mass from weight and body-fat percentage.', '{"expression":"weight * body_fat_percentage / 100","outputUnitAr":" كجم","outputUnitEn":" kg","resultLabelAr":"كتلة الدهون التقديرية","resultLabelEn":"Estimated fat mass","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية عامة ولا تغني عن استشارة مختص صحي.","noteEn":"This is a general estimate and not a substitute for professional medical advice."}'::jsonb, '[{"key":"weight","label":"الوزن بالكيلوجرام","type":"number","required":true,"min":1,"step":0.1},{"key":"body_fat_percentage","label":"نسبة الدهون","type":"number","required":true,"min":0,"max":100,"step":0.1}]'::jsonb, '[{"key":"weight","label":"Weight in kg","type":"number","required":true,"min":1,"step":0.1},{"key":"body_fat_percentage","label":"Body-fat percentage","type":"number","required":true,"min":0,"max":100,"step":0.1}]'::jsonb, 'احسب كتلة الدهون', 'Calculate fat mass', 1304, false),
