  ('health-tools', 'calorie-deficit-duration-calculator', 'حاسبة مدة عجز السعرات', 'Calorie Deficit Duration Calculator', 'قدّر عدد الأيام اللازمة لعجز طاقة محدد لكل كيلوجرام مستهدف.', 'Estimate days required for a calorie deficit target.', '{"expression":"target_kg * 7700 / daily_deficit","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"المدة التقديرية","resultLabelEn":"Estimated duration","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية عامة ولا تغني عن استشارة مختص صحي.","noteEn":"This is a general estimate and not a substitute for professional medical advice."}'::jsonb, '[{"key":"target_kg","label":"الوزن المستهدف فقده بالكيلوجرام","type":"number","required":true,"min":0,"step":0.1},{"key":"daily_deficit","label":"العجز اليومي بالسعرات","type":"number","required":true,"min":1,"step":1}]'::jsonb, '[{"key":"target_kg","label":"Target weight loss in kg","type":"number","required":true,"min":0,"step":0.1},{"key":"daily_deficit","label":"Daily calorie deficit","type":"number","required":true,"min":1,"step":1}]'::jsonb, 'احسب المدة', 'Calculate duration', 1307, false),
  ('education-tools', 'course-weighted-score-calculator', 'حاسبة الدرجة الموزونة للمقرر', 'Course Weighted Score Calculator', 'احسب الدرجة الموزونة من درجتين ونسبتيهما.', 'Calculate a weighted course score from two components.', '{"expression":"score_a * weight_a / 100 + score_b * weight_b / 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"الدرجة الموزونة","resultLabelEn":"Weighted score","decimals":2,"showEquation":true}'::jsonb, '[{"key":"score_a","label":"الدرجة الأولى","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"weight_a","label":"وزن الدرجة الأولى","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_b","label":"الدرجة الثانية","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"weight_b","label":"وزن الدرجة الثانية","type":"number","required":true,"min":0,"max":100,"step":0.01}]'::jsonb, '[{"key":"score_a","label":"First score","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"weight_a","label":"First weight","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_b","label":"Second score","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"weight_b","label":"Second weight","type":"number","required":true,"min":0,"max":100,"step":0.01}]'::jsonb, 'احسب الدرجة', 'Calculate score', 1400, true),
