  ('education-tools', 'assignment-average-calculator', 'حاسبة متوسط الواجبات', 'Assignment Average Calculator', 'احسب متوسط أربع درجات للواجبات.', 'Calculate the average of four assignment scores.', '{"expression":"(score_1 + score_2 + score_3 + score_4) / 4","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"متوسط الواجبات","resultLabelEn":"Assignment average","decimals":2,"showEquation":true}'::jsonb, '[{"key":"score_1","label":"الواجب الأول","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_2","label":"الواجب الثاني","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_3","label":"الواجب الثالث","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_4","label":"الواجب الرابع","type":"number","required":true,"min":0,"max":100,"step":0.01}]'::jsonb, '[{"key":"score_1","label":"Assignment 1","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_2","label":"Assignment 2","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_3","label":"Assignment 3","type":"number","required":true,"min":0,"max":100,"step":0.01},{"key":"score_4","label":"Assignment 4","type":"number","required":true,"min":0,"max":100,"step":0.01}]'::jsonb, 'احسب المتوسط', 'Calculate average', 1404, false),
