  ('education-tools', 'completed-credits-rate', 'حاسبة نسبة الساعات المنجزة', 'Completed Credits Rate', 'احسب نسبة الساعات الأكاديمية المنجزة من إجمالي الخطة.', 'Calculate completed academic credits as a share of the plan.', '{"expression":"completed_credits / total_credits * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة الساعات المنجزة","resultLabelEn":"Completed credits rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"completed_credits","label":"الساعات المنجزة","type":"number","required":true,"min":0,"step":1},{"key":"total_credits","label":"إجمالي ساعات الخطة","type":"number","required":true,"min":1,"step":1}]'::jsonb, '[{"key":"completed_credits","label":"Completed credits","type":"number","required":true,"min":0,"step":1},{"key":"total_credits","label":"Total plan credits","type":"number","required":true,"min":1,"step":1}]'::jsonb, 'احسب النسبة', 'Calculate rate', 1406, false),
  ('education-tools', 'points-needed-for-target', 'حاسبة النقاط المطلوبة للهدف', 'Points Needed for Target', 'احسب عدد النقاط المتبقية للوصول إلى هدف دراسي.', 'Calculate remaining points needed to reach a study target.', '{"expression":"target_points - current_points","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"النقاط المتبقية","resultLabelEn":"Remaining points","decimals":2,"showEquation":true}'::jsonb, '[{"key":"target_points","label":"النقاط المستهدفة","type":"number","required":true,"min":0,"step":0.01},{"key":"current_points","label":"النقاط الحالية","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"target_points","label":"Target points","type":"number","required":true,"min":0,"step":0.01},{"key":"current_points","label":"Current points","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب المتبقي', 'Calculate remaining', 1407, false),
