  ('employment-tools', 'annual-compensation-calculator', 'حاسبة التعويض السنوي', 'Annual Compensation Calculator', 'احسب التعويض السنوي من الراتب الشهري والمكافآت.', 'Calculate annual compensation from monthly salary and bonuses.', '{"expression":"monthly_salary * 12 + annual_bonus","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"التعويض السنوي","resultLabelEn":"Annual compensation","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_salary","label":"الراتب الشهري","type":"number","required":true,"min":0,"step":0.01},{"key":"annual_bonus","label":"المكافآت السنوية","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"monthly_salary","label":"Monthly salary","type":"number","required":true,"min":0,"step":0.01},{"key":"annual_bonus","label":"Annual bonus","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب التعويض', 'Calculate compensation', 1501, false),
  ('employment-tools', 'employer-payroll-cost', 'حاسبة تكلفة الموظف على المنشأة', 'Employer Payroll Cost', 'احسب تكلفة الموظف الشهرية بإضافة المزايا والتكاليف على الراتب.', 'Calculate monthly employer cost including benefits and overhead.', '{"expression":"salary + benefits + employer_costs","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"التكلفة الشهرية للموظف","resultLabelEn":"Monthly employer cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"salary","label":"الراتب","type":"number","required":true,"min":0,"step":0.01},{"key":"benefits","label":"المزايا الشهرية","type":"number","required":true,"min":0,"step":0.01},{"key":"employer_costs","label":"تكاليف صاحب العمل","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"salary","label":"Salary","type":"number","required":true,"min":0,"step":0.01},{"key":"benefits","label":"Monthly benefits","type":"number","required":true,"min":0,"step":0.01},{"key":"employer_costs","label":"Employer costs","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب التكلفة', 'Calculate cost', 1502, false),
