  ('employment-tools', 'commission-plus-salary', 'حاسبة الراتب مع العمولة', 'Salary plus Commission Calculator', 'احسب الدخل الشهري من الراتب الأساسي وعمولة المبيعات.', 'Calculate monthly income from base salary and sales commission.', '{"expression":"base_salary + sales * commission_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الدخل الشهري","resultLabelEn":"Monthly income","decimals":2,"showEquation":true}'::jsonb, '[{"key":"base_salary","label":"الراتب الأساسي","type":"number","required":true,"min":0,"step":0.01},{"key":"sales","label":"المبيعات","type":"number","required":true,"min":0,"step":0.01},{"key":"commission_rate","label":"نسبة العمولة","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"base_salary","label":"Base salary","type":"number","required":true,"min":0,"step":0.01},{"key":"sales","label":"Sales","type":"number","required":true,"min":0,"step":0.01},{"key":"commission_rate","label":"Commission rate","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب الدخل', 'Calculate income', 1505, false),
