  ('saudi-tools', 'end-of-service-over-five-years', 'حاسبة نهاية الخدمة بعد خمس سنوات', 'End-of-Service over Five Years', 'قدّر مكافأة نهاية الخدمة لمن تجاوزت خدمته خمس سنوات.', 'Estimate end-of-service award for service longer than five years.', '{"expression":"monthly_wage * 2.5 + monthly_wage * (years - 5)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"المكافأة التقديرية","resultLabelEn":"Estimated award","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية، ويجب مراجعة اللوائح والعقد والجهات الرسمية للحالة الفعلية.","noteEn":"This is an estimate; review the applicable regulations, contract, and official authorities."}'::jsonb, '[{"key":"monthly_wage","label":"الأجر الشهري","type":"number","required":true,"min":0,"step":0.01},{"key":"years","label":"سنوات الخدمة","type":"number","required":true,"min":5,"step":0.01}]'::jsonb, '[{"key":"monthly_wage","label":"Monthly wage","type":"number","required":true,"min":0,"step":0.01},{"key":"years","label":"Years of service","type":"number","required":true,"min":5,"step":0.01}]'::jsonb, 'احسب المكافأة', 'Calculate award', 2003, false),
  ('saudi-tools', 'housing-allowance-estimate', 'حاسبة بدل السكن', 'Housing Allowance Estimate', 'احسب بدل السكن كنسبة من الراتب الأساسي.', 'Calculate housing allowance as a percentage of base salary.', '{"expression":"basic_salary * allowance_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"بدل السكن","resultLabelEn":"Housing allowance","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية، ويجب مراجعة اللوائح والعقد والجهات الرسمية للحالة الفعلية.","noteEn":"This is an estimate; review the applicable regulations, contract, and official authorities."}'::jsonb, '[{"key":"basic_salary","label":"الراتب الأساسي","type":"number","required":true,"min":0,"step":0.01},{"key":"allowance_rate","label":"نسبة بدل السكن","type":"number","required":true,"min":0,"step":0.01,"defaultValue":25}]'::jsonb, '[{"key":"basic_salary","label":"Base salary","type":"number","required":true,"min":0,"step":0.01},{"key":"allowance_rate","label":"Housing allowance rate","type":"number","required":true,"min":0,"step":0.01,"defaultValue":25}]'::jsonb, 'احسب البدل', 'Calculate allowance', 2004, false),
  ('saudi-tools', 'annual-rent-monthly-equivalent', 'محول الإيجار السنوي إلى شهري', 'Annual Rent Monthly Equivalent', 'حوّل قيمة الإيجار السنوي إلى متوسط شهري.', 'Convert annual rent into a monthly equivalent.', '{"expression":"annual_rent / 12","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"المتوسط الشهري","resultLabelEn":"Monthly equivalent","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_rent","label":"الإيجار السنوي","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"annual_rent","label":"Annual rent","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب الإيجار الشهري', 'Calculate monthly rent', 2005, false),
  ('saudi-tools', 'thirty-day-daily-wage', 'حاسبة الأجر اليومي على أساس 30 يومًا', '30-Day Daily Wage Calculator', 'احسب الأجر اليومي بقسمة الراتب الشهري على 30 يومًا.', 'Calculate daily wage by dividing monthly salary by 30 days.', '{"expression":"monthly_salary / 30","outputUnitAr":" ر.س/يوم","outputUnitEn":" SAR/day","resultLabelAr":"الأجر اليومي","resultLabelEn":"Daily wage","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية، ويجب مراجعة اللوائح والعقد والجهات الرسمية للحالة الفعلية.","noteEn":"This is an estimate; review the applicable regulations, contract, and official authorities."}'::jsonb, '[{"key":"monthly_salary","label":"الراتب الشهري","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"monthly_salary","label":"Monthly salary","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب الأجر اليومي', 'Calculate daily wage', 2006, false),
  ('saudi-tools', 'zakat-base-estimate', 'حاسبة تقديرية للزكاة 2.5%', '2.5% Zakat Estimate', 'احسب تقديرًا بسيطًا بنسبة 2.5% من الوعاء المدخل.', 'Calculate a simple 2.5% estimate from the entered base.', '{"expression":"zakat_base * 2.5 / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الزكاة التقديرية","resultLabelEn":"Estimated zakat","decimals":2,"showEquation":true,"noteAr":"النتيجة تقديرية، ويجب مراجعة اللوائح والعقد والجهات الرسمية للحالة الفعلية.","noteEn":"This is an estimate; review the applicable regulations, contract, and official authorities."}'::jsonb, '[{"key":"zakat_base","label":"الوعاء المدخل","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, '[{"key":"zakat_base","label":"Entered base","type":"number","required":true,"min":0,"step":0.01}]'::jsonb, 'احسب التقدير', 'Calculate estimate', 2007, false);

do $$
declare
  v_seed_count integer;
  v_duplicate_count integer;
begin
  select count(*) into v_seed_count from initial_800_tool_seed;
  select count(*) - count(distinct slug) into v_duplicate_count
  from initial_800_tool_seed;

  if v_seed_count <> 88 then
    raise exception 'INITIAL_800_WAVE_SEED_COUNT_MISMATCH:%', v_seed_count;
  end if;

  if v_duplicate_count <> 0 then
    raise exception 'INITIAL_800_WAVE_DUPLICATE_SLUGS:%', v_duplicate_count;
  end if;
end;
$$;

insert into public.tools(
  slug, title_ar, title_en, short_description, category_id, engine_type,
  input_schema, output_schema, runtime_config, pricing_mode, fixed_points,
  minimum_points, requires_auth, is_featured, is_active, sort_order,
  seo_title, seo_description
)
select
  seed.slug,
  seed.title_ar,
  seed.title_en,
  seed.description_ar,
  category.id,
  'formula',
  jsonb_build_object('submitLabel', seed.submit_ar, 'fields', seed.input_fields),
  jsonb_build_object('type', 'number', 'format', 'runtime'),
  seed.runtime_config,
  'free',
  0,
  0,
  false,
  seed.is_featured,
  true,
  seed.sort_order,
  seed.title_ar || ' مجانًا | أمبراطورية الويب',
  seed.description_ar
from initial_800_tool_seed seed
join public.categories category on category.slug = seed.category_slug
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  short_description = excluded.short_description,
  category_id = excluded.category_id,
  engine_type = excluded.engine_type,
  input_schema = excluded.input_schema,
  output_schema = excluded.output_schema,
  runtime_config = excluded.runtime_config,
  pricing_mode = excluded.pricing_mode,
  fixed_points = excluded.fixed_points,
  minimum_points = excluded.minimum_points,
  requires_auth = excluded.requires_auth,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  updated_at = now();

insert into public.tool_translations(
  tool_id, locale_id, title, short_description, seo_title, seo_description,
  prompt_template_override
)
select
  tool.id,
  locale.id,
  case when locale.code = 'ar' then seed.title_ar else seed.title_en end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  case
    when locale.code = 'ar' then seed.title_ar || ' مجانًا | أمبراطورية الويب'
    else seed.title_en || ' Free | Web Empire'
  end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  null
from initial_800_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id) do update set
  title = excluded.title,
  short_description = excluded.short_description,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  prompt_template_override = null,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  field.value ->> 'key',
  field.value ->> 'label',
  nullif(field.value ->> 'placeholder', ''),
  nullif(field.value ->> 'helpText', ''),
  field.value -> 'options'
from initial_800_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
cross join lateral jsonb_array_elements(
  case when locale.code = 'ar' then seed.input_fields else seed.english_fields end
) field(value)
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = excluded.placeholder,
  help_text = excluded.help_text,
  options = excluded.options,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  '__submit__',
  case when locale.code = 'ar' then seed.submit_ar else seed.submit_en end,
  null,
  null,
  null
from initial_800_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = null,
  help_text = null,
  options = null,
  updated_at = now();

do $$
declare
  v_ready_count integer;
  v_bad_categories integer;
begin
  select count(*) into v_ready_count
  from public.tools tool
  join initial_800_tool_seed seed on seed.slug = tool.slug
  where tool.is_active = true
    and tool.engine_type = 'formula'
    and tool.pricing_mode = 'free';

  if v_ready_count <> 88 then
    raise exception 'INITIAL_800_WAVE_READY_COUNT_MISMATCH:%', v_ready_count;
  end if;

  select count(*) into v_bad_categories
  from (
    select category.slug, count(tool.id) as active_tool_count
    from public.categories category
    join public.tools tool
      on tool.category_id = category.id
     and tool.is_active = true
    where category.slug in (
      'business-tools', 'math-tools', 'marketing-tools', 'finance-tools', 'general-tools', 'converter-tools', 'date-time-tools', 'health-tools', 'education-tools', 'employment-tools', 'saudi-tools'
    )
    group by category.slug
    having count(tool.id) < 5 or count(tool.id) > 50
  ) invalid;

  if v_bad_categories <> 0 then
    raise exception 'CATEGORY_TOOL_RANGE_VIOLATION:%', v_bad_categories;
  end if;
end;
$$;

commit;

